import React, { useEffect, useState } from 'react'
import { getClientUrlDataToken } from '../../../Utils/restUtils';
import { useNavigate } from 'react-router';
import { useSelector } from 'react-redux';
import { lastAddedCustomer, lastAddedCustomerRole } from '../../../CommonUrl';
import { Spinner } from 'react-bootstrap';
import { PreCustID } from '../../../Constant';

function LastCreatedCustomerId() {
    const [customerID, setCustomerId] = useState()
    const [loading, setLoading] = useState(false)
    const navigate = useNavigate();
    const authState = useSelector((state) => state.auth);

    useEffect(() => {
        getCustomerID()
    }, [])

    const getCustomerID = async () => {
        setLoading(true)
        let data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? lastAddedCustomer : lastAddedCustomerRole);
        if (data.status === true) {
            setCustomerId(data?.data);
        }
        else if (data.status >= 400 && data.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (data.status >= 500 && data.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        }
        else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);

        }
        setLoading(false)
    };

    return (
        <>
            {
                customerID &&
                <span className='lastCustomerId mt-2' style={{ fontSize: '11px' }}>
                    {PreCustID} : {loading ? <Spinner style={{ width: "11px", height: "11px" }} /> : customerID} </span>
            }
        </>

    )
}

    export default LastCreatedCustomerId